            "X-TIMESTAMP": ts,
            "X-SIGNATURE": sig
        })

        response = requests.get(full_url, params=params, headers=headers, timeout=10)
        response.raise_for_status()
        return response.json()

    def fetch_events(self, page=1):
        url = f"{self.BASE_URL}?coCd=A420&expoChnlCd=03&startRow=0&listCount=1000"
        return self._signed_request(url)

    def fetch_special_events(self):
        url = f"{self.SAPRM_URL}/searchSaprmEvtListForPage?coCd=A420&expoChnlCd=03&startRow=0&listCount=100"
        return self._signed_request(url)

    def fetch_goods_id(self, event_id):
        url = f"{self.SAPRM_URL}/searchSaprmEvtProdList?coCd=A420&expoChnlCd=03&saprmEvntNo={event_id}"
        data = self._signed_request(url)
        if data and "data" in data and len(data["data"]) > 0:
            return data["data"][0].get("spmtlNo"), data["data"][0].get("onlnExpoNm")
        return None, None

    def fetch_inventory(self, event_id, gift_id):
        url = f"{self.SAPRM_URL}/searchSaprmEvtTgtsiteList?coCd=A420&expoChnlCd=03&saprmEvntNo={event_id}&spmtlNo={gift_id}"
        return self._signed_request(url)

    def save_event(self, event_data: dict, gift_id: str = None):
        e_id = str(event_data.get("saprmEvntNo") or event_data.get("evntNo"))
        if not e_id: return None

        event = self.session.query(Event).filter_by(EventID=e_id).first()
        if not event:
            event = Event(EventID=e_id, Operator="CGV")
            self.session.add(event)

        event.EventName = event_data.get("saprmEvntNm") or event_data.get("evntNm")
        if gift_id: event.GiftID = gift_id

        img = event_data.get("evtImgPath")
        if img:
            event.ImageUrl = f"https://img.cgv.co.kr{img}" if img.startswith("/") else img

        def parse_date(date_str):
            if not date_str: return None
            clean_date = str(date_str).replace(".", "-")[:10]
            try:
                if "-" in clean_date: return datetime.strptime(clean_date, "%Y-%m-%d").date()
                else: return datetime.strptime(clean_date, "%Y%m%d").date()
            except: return None

        new_start = parse_date(event_data.get("evntStartYmd") or event_data.get("evntStartDt") or event_data.get("saprmEvntStartYmd"))
        if new_start: event.ProgressStartDate = new_start

        new_end = parse_date(event_data.get("evntEndYmd") or event_data.get("evntEndDt") or event_data.get("saprmEvntEndYmd"))
        if new_end: event.ProgressEndDate = new_end

        self.session.commit()
        return event

    def collect_target_inventory(self, event_id: str, gift_id: str):
        inv_data = self.fetch_inventory(event_id, gift_id)
        if inv_data and "data" in inv_data:
            self._save_inventory_internal(event_id, gift_id, inv_data)
            return True
        return False

    def _save_inventory_internal(self, event_id, gift_id, inventory_data):
        items = inventory_data["data"]
        now = datetime.now()
        for item in items:
            c_id = str(item.get("siteCd") or item.get("siteNm"))
            new_count = int(item.get("rlInvntQty") or 0)
            existing = self.session.query(Inventory).filter_by(EventID=event_id, CinemaID=c_id).first()
            if not existing:
                inv = Inventory(
                    EventID=event_id, GiftID=gift_id, CinemaID=c_id,
                    CinemaName=item.get("siteNm"), DivisionName=item.get("regnGrpNm"),
                    ItemCount=new_count, LastUpdated=now
                )
                self.session.add(inv)
            else:
                existing.ItemCount = new_count
                existing.LastUpdated = now
        self.session.commit()

    def _normalize_title(self, title):
        """매칭을 위해 제목에서 특수문자와 공백을 제거하고 핵심 영화 제목만 추출 시도"""
        if not title: return ""
        # 1. 특수문자 제거
        t = re.sub(r'[^가-힣a-zA-Z0-9]', '', title)
        # 2. 공통 접두어/접미어 제거 시도
        t = t.replace("현장증정", "").replace("이벤트", "").replace("증정", "")
        return t

    def discover_new_events(self):
        logger.info("CGV Smart-Matching discovery started...")
        found = 0

        # 1. SAPRM(굿즈 실재고) 목록 수집 및 기준 생성
        saprm_events = []
        try:
            sp_data = self.fetch_special_events()
            if sp_data and "data" in sp_data and "list" in sp_data["data"]:
                for item in sp_data["data"]["list"]:
                    e_id = str(item.get("saprmEvntNo"))
                    g_id, g_name = self.fetch_goods_id(e_id)
                    event = self.save_event(item, gift_id=g_id)
                    if event:
                        saprm_events.append(event)
                        # 재고 수집도 병행
                        if g_id: self.collect_target_inventory(e_id, g_id)
                        found += 1
        except Exception as e: logger.error(f"CGV Special discovery failed: {e}")

        # 2. 일반 이벤트 목록 수집 및 SAPRM과 매칭 시도
        try:
            gen_data = self.fetch_events()
            if gen_data and "data" in gen_data and "list" in gen_data["data"]:
                for gen_item in gen_data["data"]["list"]:
                    gen_title_norm = self._normalize_title(gen_item.get("evntNm"))
                    matched = False

                    # 기존 SAPRM 이벤트 중 제목이 유사한 것이 있는지 확인
                    for saprm_event in saprm_events:
                        saprm_title_norm = self._normalize_title(saprm_event.EventName)
                        if gen_title_norm and saprm_title_norm and (gen_title_norm in saprm_title_norm or saprm_title_norm in gen_title_norm):
                            # 매칭 성공! 일반 이벤트의 배너 정보를 SAPRM 이벤트에 병합
                            logger.info(f"Matched: Gen '{gen_item.get('evntNm')}' -> SAPRM '{saprm_event.EventName}'")
                            img = gen_item.get("evtImgPath")
                            if img:
                                saprm_event.ImageUrl = f"https://img.cgv.co.kr{img}" if img.startswith("/") else img
                            matched = True
                            break

                    if not matched:
                        # 매칭 안 된 일반 이벤트는 별도 저장
                        if self.save_event(gen_item):
                            found += 1
        except Exception as e: logger.error(f"CGV General discovery failed: {e}")

        logger.info(f"CGV discovery finished. Found/Merged {found} items.")
        return found

